require "dense_array"

struct QueueItem
  row, col, time, color : Int64
end

def solve(n : Int64, m : Int64, sources : Array(Array(Int64))) : Array(Array(Int64))
  // Initialize the grid with 0 (uncolored)
  grid = Array(Array(Int64)).new(n, m) { 0 }

  // Initialize a min-priority queue based on time (shortest distance first)
  // Since we are interested in the maximum color upon arrival, a standard Dijkstra/BFS approach 
  // where we process cells in increasing order of arrival time is appropriate.
  #include "heap"
  pq = Heap.new(QueueItem)

  // Initialize sources and the grid
  sources.each do |source|
    r, c, color = source[0], source[1], source[2]

    // Since initial sources are colored at time 0
    grid[r][c] = color

    #pq.push(QueueItem(r, c, 0, color))
  end

  // While the priority queue is not empty
  while !pq.empty?
    item = #pq.pop
    r, c, time, color = item.row, item.col, item.time, item.color

    // Check if this color is worse than the current color recorded in the grid.
    // If grid[r][c] > color, it means this cell was reached earlier (or at the same time)
    // by a higher color, or this item is stale.
    // However, because we are using a PQ ordered by time, and we are propagating the *winning* color,
    // we need a mechanism to ensure we only update if the new arrival is better or if the cell is uncolored.

    // If the current grid color is greater than the arriving color, this is a stale entry from the PQ.
    if grid[r][c] > color
      next
    end

    // Directions: up, down, left, right
    directions = [[-1, 0], [1, 0], [0, -1], [0, 1]]

    directions.each do |dr, dc|
      nr = r + dr
      nc = c + dc

      // Check bounds
      if nr >= 0 && nr < n && nc >= 0 && nc < m

        next_time = time + 1

        // If the neighbor is uncolored (0) OR if the new color is greater than the existing color, 
        // we potentially update it and push to PQ.

        current_neighbor_color = grid[nr][nc]

        if current_neighbor_color == 0 || color > current_neighbor_color
          // This cell (nr, nc) will adopt 'color' at 'next_time' if no higher color beats it first.

          // Crucially, we only update the grid *if* this new arrival is strictly better than the current best.
          // If current_neighbor_color > 0, it means it has *already* been finalized or is in the process of being finalized 
          // by a path that arrived earlier/with a higher color.

          // Since we use time in the PQ, the first time a cell is reached by a color determines the time. 
          // If a later arrival with a higher color comes, we update.

          if current_neighbor_color < color
              // Update the grid color to the new, higher color.
              // This update effectively "claims" the cell with this color, even if it wasn't uncolored, 
              // because the rule is: if multiple colors arrive, the maximum wins.

              // Since we process in time order, if grid[nr][nc] was set by an earlier time T_old, 
              // and now we reach it at T_new > T_old, and color > grid[nr][nc], we should update.
              // However, the problem description implies that the cell's color is determined *at the moment* of arrival
              // based on all colors arriving at that time step.

              // A simpler interpretation for this BFS-like approach: 
              // The PQ stores (Time, Color, R, C). We want the maximum Color at minimum Time.

              // We must only push if the new arrival is better than what is currently known for this cell.

              if current_neighbor_color == 0 || color > current_neighbor_color
                // Update the grid to the winning color found so far for this cell
                if color > grid[nr][nc]
                    grid[nr][nc] = color

                    #pq.push(QueueItem(nr, nc, next_time, color))
              end
          end
        end
      end
    end
  end

  grid
end
